from sympy import isprime
from itertools import count, islice, product
def agen(): # generator of terms
    yield 3
    for d in count(3, 2):
        for rest in product("01", repeat=d//2-1):
            left = "1" + "".join(rest)
            for mid in "01":
                if isprime(t:=int(left + mid + left[::-1], 2)):
                    yield t
print(list(islice(agen(), 42))) # _Michael S. Branicky_, Jun 23 2026

